import assert from "node:assert/strict";
import test from "node:test";

import { readMessages } from "../src/messageReader.ts";
import { Utf8LineDecoder } from "../src/utf8Lines.ts";

test("a UTF-8 scalar split between chunks remains intact", () => {
  const bytes = new TextEncoder().encode('{"name":"caf\u00e9"}\n');
  const lead = bytes.indexOf(0xc3);
  const decoder = new Utf8LineDecoder();

  assert.deepEqual(decoder.push(bytes.slice(0, lead + 1)), []);
  assert.deepEqual(decoder.push(bytes.slice(lead + 1)), ['{"name":"caf\u00e9"}']);
});

test("a complete final JSON record does not require a newline", () => {
  const messages = readMessages([
    new TextEncoder().encode('{"id":7,"status":"closed"}'),
  ]);

  assert.deepEqual(messages, [{ id: 7, status: "closed" }]);
});
